+            }
+        }
+        return frequencies;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
+    {
+        var words = TokenizeWords(sentence);
+        if (words.Length == 0) return 0;
+
+        double score = 0;
+        foreach (var word in words)
+        {
+            if (wordFrequencies.TryGetValue(word, out int freq))
+                score += freq;
+        }
+        return score / words.Length;
+    }
+
+    private static string[] TokenizeWords(string text)
+    {
+        return WordPattern().Matches(text)
+            .Select(m => m.Value.ToLowerInvariant())
+            .ToArray();
+    }
